import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Box,
  Typography,
  Container,
  Stack,
  Alert,
  CircularProgress,
  Button,
  Card,
  CardContent,
  Chip,
  Grid,
  IconButton,
  Tooltip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
} from '@mui/material';
import {
  Download,
  Edit,
  Delete,
  Share,
  Person,
  School,
  Tag,
  Description,
  FileDownload,
  Link,
  TrendingUp,
  Psychology,
  Assessment,
  ExpandMore,
} from '@mui/icons-material';
import { useGetPaperByIdQuery, useDeletePaperMutation } from '@/services/api/papersApi';
import { useAuth } from '@/hooks/useAuth';
import { formatDate, formatRelativeDate } from '@/utils/helpers/dateUtils';
import { ROUTES } from '@/utils/constants/routes';
import PDFPreview from '@/components/papers/PDFPreview';

const PaperDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);

  const {
    data: paperData,
    isLoading: paperLoading,
    error: paperError,
  } = useGetPaperByIdQuery(id!);

  const [deletePaper, { isLoading: deleteLoading }] = useDeletePaperMutation();

  const paper = paperData?.data.paper;

  const handleEdit = () => {
    if (paper) {
      navigate(ROUTES.PAPERS.EDIT(paper._id));
    }
  };

  const handleDelete = () => {
    setDeleteDialogOpen(true);
  };

  const confirmDelete = async () => {
    if (paper) {
      try {
        await deletePaper(paper._id).unwrap();
        navigate(ROUTES.PAPERS.MY_PAPERS);
      } catch (error) {
        console.error('Failed to delete paper:', error);
      }
    }
  };

  const handleDownload = () => {
    // Handle download logic
    console.log('Downloading paper:', paper?.title);
  };

  const handleShare = () => {
    if (paper) {
      navigator.clipboard.writeText(window.location.href);
      // Could show a snackbar notification here
    }
  };

  const isOwner = user?.id === paper?.uploadedBy._id;

  if (paperLoading) {
    return (
      <Container maxWidth="lg" sx={{ py: 4 }}>
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
          <CircularProgress />
        </Box>
      </Container>
    );
  }

  if (paperError || !paper) {
    return (
      <Container maxWidth="lg" sx={{ py: 4 }}>
        <Alert severity="error">
          Paper not found or you don't have permission to view it.
        </Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={3}>
        {/* Header */}
        <Box>
          <Stack direction="row" justifyContent="space-between" alignItems="flex-start" sx={{ mb: 2 }}>
            <Box sx={{ flex: 1 }}>
              <Typography variant="h4" component="h1" gutterBottom>
                {paper.title}
              </Typography>
              <Stack direction="row" spacing={2} alignItems="center" sx={{ mb: 2 }}>
                <Chip
                  label={paper.isPublic ? 'Public' : 'Private'}
                  color={paper.isPublic ? 'success' : 'default'}
                  size="small"
                />
                <Typography variant="body2" color="text.secondary">
                  Uploaded {formatRelativeDate(paper.createdAt)}
                </Typography>
              </Stack>
            </Box>
            <Stack direction="row" spacing={1}>
              <Tooltip title="Download">
                <IconButton onClick={handleDownload}>
                  <Download />
                </IconButton>
              </Tooltip>
              <Tooltip title="Share">
                <IconButton onClick={handleShare}>
                  <Share />
                </IconButton>
              </Tooltip>
              {isOwner && (
                <>
                  <Tooltip title="Edit">
                    <IconButton onClick={handleEdit}>
                      <Edit />
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="Delete">
                    <IconButton onClick={handleDelete} color="error">
                      <Delete />
                    </IconButton>
                  </Tooltip>
                </>
              )}
            </Stack>
          </Stack>
        </Box>

        <Grid container spacing={3}>
          {/* Main Content */}
          <Grid item xs={12} lg={8}>
            <Stack spacing={3}>
              {/* Summary Section (1st) */}
              <Card>
                <CardContent>
                  <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                    <Description color="primary" />
                    <Typography variant="h6">Summary</Typography>
                  </Stack>
                  
                  {/* Abstract */}
                  {paper.abstract && (
                    <Box sx={{ mb: 3 }}>
                      <Typography variant="subtitle1" gutterBottom>
                        Abstract
                      </Typography>
                      <Typography variant="body1" sx={{ lineHeight: 1.6 }}>
                        {paper.abstract}
                      </Typography>
                    </Box>
                  )}

                  {/* Detailed Summary */}
                  {paper.detailed_summary && (
                    <Box>
                      <Typography variant="subtitle1" gutterBottom>
                        Detailed Summary
                      </Typography>
                      <Typography variant="body1" sx={{ lineHeight: 1.6 }}>
                        {paper.detailed_summary}
                      </Typography>
                    </Box>
                  )}
                </CardContent>
              </Card>

              {/* PDF Preview Section (2nd) */}
              <PDFPreview
                pdfUrl={paper.fileUrl}
                fileName={paper.fileName}
                isLoading={paperLoading}
                error={paperError ? 'Failed to load PDF' : undefined}
              />

              {/* AI Analysis Section (3rd) */}
              {paper.gemini_analysis && (
                <Card>
                  <CardContent>
                    <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                      <Psychology color="primary" />
                      <Typography variant="h6">Research Analysis</Typography>
                    </Stack>
                    <Accordion>
                      <AccordionSummary expandIcon={<ExpandMore />}>
                        <Typography variant="subtitle1">Detailed Analysis</Typography>
                      </AccordionSummary>
                      <AccordionDetails>
                        <Stack spacing={2}>
                          {paper.gemini_analysis.research_area && (
                            <Box>
                              <Typography variant="subtitle2" gutterBottom>
                                Research Area
                              </Typography>
                              <Typography variant="body2">
                                {paper.gemini_analysis.research_area}
                              </Typography>
                            </Box>
                          )}
                          {paper.gemini_analysis.methodology && (
                            <Box>
                              <Typography variant="subtitle2" gutterBottom>
                                Methodology
                              </Typography>
                              <Typography variant="body2">
                                {paper.gemini_analysis.methodology}
                              </Typography>
                            </Box>
                          )}
                          {paper.gemini_analysis.key_findings && paper.gemini_analysis.key_findings.length > 0 && (
                            <Box>
                              <Typography variant="subtitle2" gutterBottom>
                                Key Findings
                              </Typography>
                              <List dense>
                                {paper.gemini_analysis.key_findings.map((finding, index) => (
                                  <ListItem key={index}>
                                    <ListItemIcon>
                                      <TrendingUp fontSize="small" />
                                    </ListItemIcon>
                                    <ListItemText primary={finding} />
                                  </ListItem>
                                ))}
                              </List>
                            </Box>
                          )}
                          {paper.gemini_analysis.research_impact && (
                            <Box>
                              <Typography variant="subtitle2" gutterBottom>
                                Research Impact
                              </Typography>
                              <Typography variant="body2">
                                {paper.gemini_analysis.research_impact}
                              </Typography>
                            </Box>
                          )}
                        </Stack>
                      </AccordionDetails>
                    </Accordion>
                  </CardContent>
                </Card>
              )}

              {/* Additional Information */}
              <Stack spacing={3}>
                {/* Authors */}
                <Card>
                  <CardContent>
                    <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                      <Person color="primary" />
                      <Typography variant="h6">Authors</Typography>
                    </Stack>
                    <Typography variant="body1">
                      {paper.authors.join(', ')}
                    </Typography>
                  </CardContent>
                </Card>

                {/* Journal Information */}
                {paper.journalName && (
                  <Card>
                    <CardContent>
                      <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                        <School color="primary" />
                        <Typography variant="h6">Journal</Typography>
                      </Stack>
                      <Typography variant="body1">
                        {paper.journalName}
                      </Typography>
                      {paper.publication_date && (
                        <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                          Published: {formatDate(paper.publication_date)}
                        </Typography>
                      )}
                    </CardContent>
                  </Card>
                )}

                {/* Keywords */}
                {paper.keywords && paper.keywords.length > 0 && (
                  <Card>
                    <CardContent>
                      <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                        <Tag color="primary" />
                        <Typography variant="h6">Keywords</Typography>
                      </Stack>
                      <Stack direction="row" spacing={1} flexWrap="wrap">
                        {paper.keywords.map((keyword, index) => (
                          <Chip
                            key={index}
                            label={keyword}
                            variant="outlined"
                            size="small"
                          />
                        ))}
                      </Stack>
                    </CardContent>
                  </Card>
                )}
              </Stack>
            </Stack>
          </Grid>

          {/* Sidebar */}
          <Grid item xs={12} lg={4}>
            <Stack spacing={3}>
              {/* File Information */}
              <Card>
                <CardContent>
                  <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                    <FileDownload color="primary" />
                    <Typography variant="h6">File Information</Typography>
                  </Stack>
                  <List dense>
                    <ListItem>
                      <ListItemText
                        primary="File Name"
                        secondary={paper.fileName}
                      />
                    </ListItem>
                    <ListItem>
                      <ListItemText
                        primary="File Size"
                        secondary={paper.formattedFileSize}
                      />
                    </ListItem>
                    <ListItem>
                      <ListItemText
                        primary="File Type"
                        secondary={paper.mimeType}
                      />
                    </ListItem>
                    <ListItem>
                      <ListItemText
                        primary="Downloads"
                        secondary={paper.downloadCount}
                      />
                    </ListItem>
                  </List>
                </CardContent>
              </Card>

              {/* Upload Information */}
              <Card>
                <CardContent>
                  <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                    <Person color="primary" />
                    <Typography variant="h6">Uploaded By</Typography>
                  </Stack>
                  <Typography variant="body1" gutterBottom>
                    {paper.uploadedBy.username}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {formatDate(paper.createdAt)}
                  </Typography>
                </CardContent>
              </Card>

              {/* Processing Information */}
              {paper.processing_info && (
                <Card>
                  <CardContent>
                    <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
                      <Assessment color="primary" />
                      <Typography variant="h6">Processing Info</Typography>
                    </Stack>
                    <List dense>
                      {paper.processing_info.extraction_method && (
                        <ListItem>
                          <ListItemText
                            primary="Extraction Method"
                            secondary={paper.processing_info.extraction_method}
                          />
                        </ListItem>
                      )}
                      {paper.processing_info.ai_processing_time && (
                        <ListItem>
                          <ListItemText
                            primary="AI Processing Time"
                            secondary={`${paper.processing_info.ai_processing_time}ms`}
                          />
                        </ListItem>
                      )}
                      {paper.processing_info.gemini_tokens_used && (
                        <ListItem>
                          <ListItemText
                            primary="Tokens Used"
                            secondary={paper.processing_info.gemini_tokens_used.toLocaleString()}
                          />
                        </ListItem>
                      )}
                      {paper.processing_info.confidence_score && (
                        <ListItem>
                          <ListItemText
                            primary="Confidence Score"
                            secondary={`${(paper.processing_info.confidence_score * 100).toFixed(1)}%`}
                          />
                        </ListItem>
                      )}
                    </List>
                  </CardContent>
                </Card>
              )}

              {/* Actions */}
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>
                    Actions
                  </Typography>
                  <Stack spacing={2}>
                    <Button
                      variant="contained"
                      startIcon={<Download />}
                      onClick={handleDownload}
                      fullWidth
                    >
                      Download Paper
                    </Button>
                    {paper.paperLink && (
                      <Button
                        variant="outlined"
                        startIcon={<Link />}
                        href={paper.paperLink}
                        target="_blank"
                        fullWidth
                      >
                        View Original
                      </Button>
                    )}
                    {isOwner && (
                      <Button
                        variant="outlined"
                        startIcon={<Edit />}
                        onClick={handleEdit}
                        fullWidth
                      >
                        Edit Paper
                      </Button>
                    )}
                  </Stack>
                </CardContent>
              </Card>
            </Stack>
          </Grid>
        </Grid>
      </Stack>

      {/* Delete Confirmation Dialog */}
      <Dialog
        open={deleteDialogOpen}
        onClose={() => setDeleteDialogOpen(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>Delete Paper</DialogTitle>
        <DialogContent>
          <Typography>
            Are you sure you want to delete "{paper.title}"? This action cannot be undone.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={() => setDeleteDialogOpen(false)}
            disabled={deleteLoading}
          >
            Cancel
          </Button>
          <Button
            onClick={confirmDelete}
            color="error"
            variant="contained"
            disabled={deleteLoading}
          >
            {deleteLoading ? <CircularProgress size={20} /> : 'Delete'}
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default PaperDetailPage;