import React from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Alert,
  CircularProgress,
} from '@mui/material';
import { PictureAsPdf } from '@mui/icons-material';

interface PDFPreviewProps {
  pdfUrl?: string;
  fileName?: string;
  isLoading?: boolean;
  error?: string;
}

const PDFPreview: React.FC<PDFPreviewProps> = ({
  pdfUrl,
  fileName,
  isLoading = false,
  error,
}) => {
  if (isLoading) {
    return (
      <Card>
        <CardContent>
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
            <CircularProgress />
          </Box>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent>
          <Alert severity="error">
            {error}
          </Alert>
        </CardContent>
      </Card>
    );
  }

  if (!pdfUrl) {
    return (
      <Card>
        <CardContent>
          <Box sx={{ textAlign: 'center', py: 4 }}>
            <PictureAsPdf sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
            <Typography variant="h6" color="text.secondary" gutterBottom>
              PDF Preview Not Available
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {fileName ? `File: ${fileName}` : 'No PDF file available for preview'}
            </Typography>
          </Box>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardContent>
        <Box sx={{ mb: 2 }}>
          <Typography variant="h6" gutterBottom>
            PDF Preview
          </Typography>
          {fileName && (
            <Typography variant="body2" color="text.secondary">
              {fileName}
            </Typography>
          )}
        </Box>
        <Box
          sx={{
            width: '100%',
            height: '600px',
            border: '1px solid',
            borderColor: 'divider',
            borderRadius: 1,
            overflow: 'hidden',
          }}
        >
          <iframe
            src={`${pdfUrl}#toolbar=0&navpanes=0&scrollbar=0`}
            width="100%"
            height="100%"
            title="PDF Preview"
            style={{ border: 'none' }}
          />
        </Box>
      </CardContent>
    </Card>
  );
};

export default PDFPreview; 